from collections import deque

def crawl_bfs(seed_url, fetch_page, max_pages=1000):
    visited = set()
    queue = deque([seed_url])
    while queue and len(visited) < max_pages:
        url = queue.popleft()
        if url in visited:
            continue
        visited.add(url)
        links = fetch_page(url)
        for link in links:
            if link not in visited:
                queue.append(link)
    return visited
